HRESULT MRFTWISetSelectShow::SelectShowPostProcess(CATPathElement *iPathElt,CATShowAttribut iShowAttr) 
{
	HRESULT rc = E_FAIL;
	CATINavigateObject_var spNavigateObject = this;
	if (spNavigateObject != NULL_var)
	{
		CATLISTV(CATBaseUnknown_var)* pListChildren = spNavigateObject->GetChildren();
		if (NULL != pListChildren)
		{
			int size = pListChildren->Size();
			if (size > 0)
			{
				for (int i = 1; i <= size; i++)
				{
					CATBaseUnknown_var spTWIObject = (*pListChildren)[i];
					if (NULL_var != spTWIObject)
					{
						CATIVisProperties_var spVentProperties = spTWIObject;
						if (NULL_var != spVentProperties)
						{
							CATVisPropertiesValues VisPropValues;
							rc = spVentProperties->GetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType);
							if (SUCCEEDED(rc))
							{
								VisPropValues.SetShow(iShowAttr);
								rc = spVentProperties->SetPropertiesAtt(VisPropValues, CATVPShow, CATVPGlobalType);

								CATIModelEvents_var spModelEvents = spTWIObject;
								if (SUCCEEDED(rc) && NULL_var != spModelEvents)
								{
									CATModifyVisProperties ModifyNotification(spTWIObject, NULL, CATVPGlobalType, CATVPShow, VisPropValues);
									spModelEvents->Dispatch(ModifyNotification);
								}
							}
						}
					}
				}
			}
		}
	}

	CATIMmiMechanicalFeature_var spMechFeat = this;
	if (NULL_var != spMechFeat)
	{
		CATIMmiMechanicalFeature_var spPart;
		rc = spMechFeat->GetMechanicalPart(spPart);

		if (NULL_var != spPart)
		{
			CATIMmiPartModelEventManagement_var spPrtMgt = spPart;
			if (NULL_var != spPrtMgt)
			{
				spPrtMgt->CommitNow();
				rc = S_OK;
			}
			else
			{
				rc = E_FAIL;
			}
		}
	}

	return rc;
} 






